script:
frappe.ui.form.on('Item', {
    custom_loyalty_points: function(frm) {
        if (frm.doc.custom_loyalty_points > 100) {
            frappe.msgprint({
                title: 'High Loyalty Points',
                message: `Loyalty points (${frm.doc.custom_loyalty_points}) is above 100. Are you sure?`,
                indicator: 'orange'
            });
        }
    },

    validate: function(frm) {
        if (frm.doc.custom_loyalty_points < 0) {
            frappe.throw('Loyalty Points cannot be negative.');
        }
    }
});
